    #[tokio::test]
    async fn client_tunnel_subdomain_is_immutable_after_first_claim() {
        let (store, config) = setup_store("client-tunnel-subdomain-immutable").await;
        let installation_id = "inst-client-subdomain-immutable";
        let signing_key = insert_signed_installation(&store, installation_id).await;
        let initial = ClientTunnelConfig {
            owner_email: "owner@example.com".into(),
            subdomain: "client-alpha".into(),
            enabled: true,
        };
        let timestamp_ms = Utc::now().timestamp_millis();
        let nonce = Uuid::new_v4().to_string();
        let signature = sign_test_payload(
            &signing_key,
            installation_id,
            "client_tunnel_claim",
            &initial,
            timestamp_ms,
            &nonce,
        );
        store
            .claim_client_tunnel(
                &config,
                ClientTunnelClaimRequest {
                    installation_id: installation_id.into(),
                    timestamp_ms,
                    nonce,
                    signature,
                    tunnel: initial,
                },
                ClientMetadata {
                    ip: None,
                    country_code: None,
                },
            )
            .await
            .expect("first Client subdomain claim must succeed");

        let same_subdomain = ClientTunnelConfig {
            owner_email: "owner@example.com".into(),
            subdomain: "client-alpha".into(),
            enabled: false,
        };
        let timestamp_ms = Utc::now().timestamp_millis();
        let nonce = Uuid::new_v4().to_string();
        let signature = sign_test_payload(
            &signing_key,
            installation_id,
            "client_tunnel_update",
            &same_subdomain,
            timestamp_ms,
            &nonce,
        );
        store
            .update_client_tunnel(
                &config,
                ClientTunnelUpdateRequest {
                    installation_id: installation_id.into(),
                    timestamp_ms,
                    nonce,
                    signature,
                    tunnel: same_subdomain,
                },
                ClientMetadata {
                    ip: None,
                    country_code: None,
                },
            )
            .await
            .expect("status update with the same Client subdomain must succeed");

        let replacement = ClientTunnelConfig {
            owner_email: "owner@example.com".into(),
            subdomain: "client-beta".into(),
            enabled: true,
        };
        let timestamp_ms = Utc::now().timestamp_millis();
        let nonce = Uuid::new_v4().to_string();
        let signature = sign_test_payload(
            &signing_key,
            installation_id,
            "client_tunnel_update",
            &replacement,
            timestamp_ms,
            &nonce,
        );
        let error = store
            .update_client_tunnel(
                &config,
                ClientTunnelUpdateRequest {
                    installation_id: installation_id.into(),
                    timestamp_ms,
                    nonce,
                    signature,
                    tunnel: replacement,
                },
                ClientMetadata {
                    ip: None,
                    country_code: None,
                },
            )
            .await
            .expect_err("a different Client subdomain must be rejected");
        assert!(error.to_string().contains("client_subdomain_immutable"));

        let conn = store.conn.lock().await;
        let stored = get_client_tunnel_by_installation(&conn, installation_id)
            .expect("read Client tunnel")
            .expect("Client tunnel exists");
        assert_eq!(stored.subdomain, "client-alpha");
        assert!(!stored.enabled);
        drop(conn);
        let _ = std::fs::remove_file(PathBuf::from(config.db_path));
    }

    #[tokio::test]
    async fn change_installation_owner_email_uses_new_owner_session() {
        let (store, config) = setup_store("change-owner-session").await;
        let installation_id = "inst-change-owner";
        let signing_key = insert_signed_installation(&store, installation_id).await;
        insert_share(
            &store,
            installation_id,
            "share-change-owner",
            "change-owner",
            "paused",
        )
        .await;
        insert_share(
            &store,
            installation_id,
            "share-divergent-owner",
            "divergent-owner",
            "paused",
        )
        .await;
        let old_email = "owner@example.com";
        let new_email = "new-owner@example.com";
        insert_client_tunnel(&store, installation_id, old_email, "change-owner-client").await;
        let access_token = "access-token-for-change-owner";
        let now = Utc::now();
        {
            let conn = store.conn.lock().await;
            conn.execute(
                "UPDATE shares SET owner_email = 'historical@example.com', shared_with_emails_json = '[]'
                 WHERE share_id = 'share-divergent-owner'",
                [],
            )
            .expect("seed divergent share owner");
            let user = upsert_user_by_email(&conn, new_email, now).expect("upsert user");
            persist_session(
                &conn,
                &AuthSession {
                    session_id: Uuid::new_v4().to_string(),
                    user_id: user.id,
                    email: new_email.into(),
                    installation_id: installation_id.into(),
                    access_token_hash: hash_token(access_token),
                    refresh_token_hash: hash_token("refresh-token-for-change-owner"),
                    access_expires_at: now + Duration::hours(1),
                    refresh_expires_at: now + Duration::days(1),
                    created_at: now,
                    last_used_at: now,
                },
            )
            .expect("persist session");
        }

        let timestamp_ms = Utc::now().timestamp_millis();
        let nonce = Uuid::new_v4().to_string();
        let payload = ChangeOwnerEmailSignaturePayload {
            old_email,
            new_email,
        };
        let signature = sign_test_payload(
            &signing_key,
            installation_id,
            "change_installation_owner_email",
            &payload,
            timestamp_ms,
            &nonce,
        );

        let response = store
            .change_installation_owner_email(
                ChangeInstallationOwnerEmailRequest {
                    installation_id: installation_id.into(),
                    old_email: old_email.into(),
                    new_email: new_email.into(),
                    timestamp_ms,
                    nonce,
                    signature,
                },
                Some(access_token),
            )
            .await
            .expect("change owner email");

        assert!(response.ok);
        assert_eq!(response.old_email, old_email);
        assert_eq!(response.new_email, new_email);
        assert_eq!(response.updated_shares, 2);
        let conn = store.conn.lock().await;
        assert_eq!(
            get_installation_owner_email(&conn, installation_id).expect("owner email"),
            Some(new_email.into())
        );
        assert_eq!(
            get_share_owner_email(&conn, "share-change-owner").expect("share owner"),
            Some(new_email.into())
        );
        assert_eq!(
            get_share_owner_email(&conn, "share-divergent-owner").expect("divergent share owner"),
            Some(new_email.into())
        );
        let tunnel_owner: String = conn
            .query_row(
                "SELECT owner_email FROM installation_client_tunnels WHERE installation_id = ?1",
                params![installation_id],
                |row| row.get(0),
            )
            .expect("read rebound client tunnel owner");
        assert_eq!(tunnel_owner, new_email);
        let shared_json: String = conn
            .query_row(
                "SELECT shared_with_emails_json FROM shares WHERE share_id = 'share-divergent-owner'",
                [],
                |row| row.get(0),
            )
            .expect("read migrated share ACL");
        let shared: Vec<String> = serde_json::from_str(&shared_json).expect("parse migrated ACL");
        assert_eq!(shared, vec!["historical@example.com".to_string()]);
        drop(conn);
        assert_eq!(
            store
                .resolve_client_tunnel_owner_email("change-owner-client", Some(installation_id))
                .await
                .expect("resolve rebound client tunnel owner")
                .as_deref(),
            Some(new_email)
        );
        let _ = std::fs::remove_file(PathBuf::from(config.db_path));
    }

