        let snapshot = store
            .dashboard_snapshot(&config, &server_geo, &proxy, None)
            .await
            .expect("dashboard snapshot");

        assert_eq!(snapshot.stats.clients, 1);
        assert_eq!(snapshot.stats.active_shares, 0);
